@startuml
skinparam classAttributeIconSize 0
skinparam packageStyle rectangle
skinparam backgroundColor #FFFFFF
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #000000
  HeaderBackgroundColor #F5F5F5
  HeaderBorderColor #000000
  HeaderFontColor #000000
  FontColor #000000
  ArrowColor #000000
}
skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeCBorderColor #000000
skinparam stereotypeCFontColor #000000

class "Scanner" as Scanner {
  + ExactToken()
}
class "Parser" as Parser {
  + paser()
  + getDErrorCount() : int
}
class "PascalScanner" as PascalScanner {
  + ExactToken()
}
class "PascalParserTd" as PascalParserTd {
  + paser()
  + getDErrorCount() : int
}

PascalScanner --|> Scanner
PascalParserTd --|> Parser

package "frontend" as frontend {
  package "pascal" as pascal {
    class "PascalParserTd" as PascalParserTd2 {
    }
    class "PascalScanner" as PascalScanner2 {
    }
    class "Parser" as Parser2 {
    }
    class "Scanner" as Scanner2 {
    }
  }
}

@enduml
